package com.example.demo.controller;

import org.springframework.beans.factory.annotation.Value;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.multipart.MultipartFile;

import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.UUID;

@RestController
@RequestMapping("/api/profile")
public class ProfilePictureController {

    @Value("${upload.directory}")
    private String uploadDirectory;

    @PostMapping("/upload")
    public ResponseEntity<?> uploadProfilePicture(@RequestParam("file") MultipartFile file) {
        if (file.isEmpty()) {
            return ResponseEntity.badRequest().body("File is empty");
        }

        // Validate file type
        String contentType = file.getContentType();
        if (contentType == null || !isValidImageType(contentType)) {
            return ResponseEntity.badRequest().body("Invalid file type. Only image files are allowed.");
        }

        // Validate file size (max 5MB)
        if (file.getSize() > 5 * 1024 * 1024) {
            return ResponseEntity.badRequest().body("File size exceeds 5MB limit");
        }

        try {
            // Create upload directory if it doesn't exist
            Path uploadPath = Paths.get(uploadDirectory);
            Files.createDirectories(uploadPath);

            // Generate unique filename
            String originalFileName = file.getOriginalFilename();
            String extension = getFileExtension(originalFileName);
            if (extension == null || !isValidImageExtension(extension)) {
                return ResponseEntity.badRequest().body("Invalid file extension");
            }

            String uniqueFileName = UUID.randomUUID().toString() + "." + extension;
            Path filePath = uploadPath.resolve(uniqueFileName);

            // Save file
            file.transferTo(filePath.toFile());

            // Return file URL
            String fileUrl = "/uploads/" + uniqueFileName;
            return ResponseEntity.ok().body(new FileUploadResponse(fileUrl));

        } catch (IOException e) {
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body("Failed to upload file");
        }
    }

    private boolean isValidImageType(String contentType) {
        return contentType != null && contentType.startsWith("image/");
    }

    private boolean isValidImageExtension(String extension) {
        if (extension == null) return false;
        String lowerExt = extension.toLowerCase();
        return "jpg".equals(lowerExt) || "jpeg".equals(lowerExt) || 
               "png".equals(lowerExt) || "gif".equals(lowerExt) || 
               "webp".equals(lowerExt);
    }

    private String getFileExtension(String fileName) {
        if (fileName == null) return null;
        int lastDotIndex = fileName.lastIndexOf('.');
        if (lastDotIndex > 0) {
            return fileName.substring(lastDotIndex + 1);
        }
        return null;
    }

    private static class FileUploadResponse {
        private final String url;

        public FileUploadResponse(String url) {
            this.url = url;
        }

        public String getUrl() {
            return url;
        }
    }
}